using System.Diagnostics;
using System.Runtime.CompilerServices;
using System.Runtime.InteropServices;
using TextAnalysis;

// Build a deterministic ~500-word input
var rng = new Random(42);
var words = new string[500];
for (int i = 0; i < words.Length; i++)
{
    int len = rng.Next(1, 15);
    char[] buf = new char[len];
    for (int j = 0; j < len; j++)
        buf[j] = (char)('a' + rng.Next(0, 26));
    words[i] = new string(buf);
}
var analyzer = new TextAnalyzer(string.Join(' ', words));

string runtime = RuntimeInformation.FrameworkDescription;
Console.WriteLine($"Runtime: {runtime}");
Console.WriteLine($"{"Method",-25} {"Mean",12} {"Iterations",12}");
Console.WriteLine(new string('-', 51));

Bench("AverageWordLength",  () => analyzer.AverageWordLength());
Bench("WordLengthHistogram", () => analyzer.WordLengthHistogram());
Bench("UniqueWordCount",    () => analyzer.UniqueWordCount());

// Simple micro-benchmark: warm up, then measure enough iterations
// to get a stable per-call time.
static void Bench(string name, Action action)
{
    // Warmup
    for (int i = 0; i < 1000; i++) action();

    // Determine iteration count: run for at least 2 seconds
    const double targetSeconds = 2.0;
    int iterations = 1000;
    Stopwatch sw;

    // Auto-scale iterations
    while (true)
    {
        sw = Stopwatch.StartNew();
        for (int i = 0; i < iterations; i++) action();
        sw.Stop();
        if (sw.Elapsed.TotalSeconds >= targetSeconds) break;
        iterations = (int)(iterations * (targetSeconds / sw.Elapsed.TotalSeconds) * 1.1);
    }

    double nsPerOp = sw.Elapsed.TotalNanoseconds / iterations;
    string unit;
    double value;
    if (nsPerOp < 1_000)       { value = nsPerOp;           unit = "ns"; }
    else if (nsPerOp < 1_000_000) { value = nsPerOp / 1_000; unit = "µs"; }
    else                          { value = nsPerOp / 1_000_000; unit = "ms"; }

    Console.WriteLine($"{name,-25} {value,9:F2} {unit,-2} {iterations,12:N0}");
}

